    return f'''<aside class="side"><a class="sideBrand" href="/"><div class="smallLogo"></div><b>Nina<span class="os">OS</span></b></a><nav class="nav">{nav}</nav><div class="userMini"><div class="avatar">K</div><div><b>Katrin</b><br><small style="color:var(--muted)">Owner</small></div></div></aside>'''

