def network_block():
    return '''<section class="block"><div class="blockHead"><h2>Global Network</h2><small>View network →</small></div><div class="map"><div class="dot" style="left:15%;top:44%"></div><div class="dot" style="left:23%;top:54%"></div><div class="dot" style="left:44%;top:43%"></div><div class="dot" style="left:57%;top:32%"></div><div class="dot" style="left:72%;top:46%"></div><div class="dot" style="left:85%;top:58%"></div></div><div class="stats"><div class="stat"><b>12,458</b><span>AI Workers Online</span></div><div class="stat"><b>1,247</b><span>Workspaces</span></div><div class="stat"><b>98</b><span>Countries</span></div><div class="stat"><b>2.4M</b><span>Tasks Completed Today</span></div></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:12px"><div class="item">Nina Estimator completed estimate<span>2 min ago</span></div><div class="item">Nina Sales closed a deal<span>5 min ago</span></div><div class="item">Nina Office Manager scheduled meeting<span>8 min ago</span></div><div class="item">Nina Support resolved ticket<span>10 min ago</span></div></div></section>'''

def page(body):
    return f'''<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>NinaOS</title>{CSS}</head><body><div class="wrap">{body}<nav class="mobileNav"><a class="active" href="/dashboard">Dashboard</a><a href="/workers">Workers</a><a href="/office-manager">Nina</a><a href="/exchange">Exchange</a></nav></div></body></html>'''

@app.route("/")
@app.route("/dashboard")
def home():
    return page(f'''<div class="target">{brand_panel()}{dashboard_inner()}</div><div class="bottom">{mobile_block()}{exchange_block()}{network_block()}</div>''')

@app.route("/workers")
def workers():
    cards = "".join(worker_card(w) for w in WORKERS)
